def binary_search(arr: list, target: int) -> int:
    low, high = 0, len(arr) - 1
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1


class TestBinarySearchHappyPath:
    """Tests for typical, expected use cases."""

    def test_target_found_in_middle(self):
        arr = [1, 2, 3, 4, 5, 6, 7]
        assert binary_search(arr, 4) == 3

    def test_target_at_start(self):
        arr = [1, 2, 3, 4, 5]
        assert binary_search(arr, 1) == 0

    def test_target_at_end(self):
        arr = [1, 2, 3, 4, 5]
        assert binary_search(arr, 5) == 4

    def test_target_not_found_returns_negative_one(self):
        arr = [1, 2, 3, 4, 5]
        assert binary_search(arr, 10) == -1

    def test_target_smaller_than_all_elements(self):
        arr = [10, 20, 30, 40]
        assert binary_search(arr, 5) == -1

    def test_target_larger_than_all_elements(self):
        arr = [10, 20, 30, 40]
        assert binary_search(arr, 50) == -1

    def test_target_between_elements_not_present(self):
        arr = [1, 3, 5, 7, 9]
