    def test_empty_array_target_zero(self):
        assert binary_search([], 0) == -1

    def test_single_element_array_match(self):
        assert binary_search([42], 42) == 0

    def test_single_element_array_no_match(self):
        assert binary_search([42], 99) == -1

    def test_single_element_array_smaller_target(self):
        assert binary_search([42], 1) == -1

    def test_two_element_array_first(self):
        assert binary_search([1, 2], 1) == 0

    def test_two_element_array_second(self):
        assert binary_search([1, 2], 2) == 1

    def test_two_element_array_not_found(self):
        assert binary_search([1, 2], 3) == -1

    def test_duplicates_returns_some_valid_index(self):
        # With duplicates, return value should point to a matching element
        arr = [1, 2, 2, 2, 3]
        result = binary_search(arr, 2)
        assert arr[result] == 2
        assert result in (1, 2, 3)

    def test_all_same_elements_target_match(self):
