        assert binary_search(arr, 4) == -1

    def test_large_integers(self):
        arr = [10**18, 10**18 + 1, 10**18 + 2]
        assert binary_search(arr, 10**18 + 1) == 1

    def test_negative_target_not_in_positive_array(self):
        arr = [1, 2, 3, 4, 5]
        assert binary_search(arr, -1) == -1


class TestBinarySearchErrorCases:
    """Tests for invalid inputs that should raise exceptions."""

    def test_none_array_raises_type_error(self):
        with pytest.raises(TypeError):
            binary_search(None, 5)

    def test_string_in_array_raises_type_error(self):
        # Comparing int to str raises TypeError in Python 3
        with pytest.raises(TypeError):
            binary_search([1, 2, "three", 4], 3)

    def test_none_in_array_raises_type_error(self):
        with pytest.raises(TypeError):
            binary_search([1, 2, None, 4], 3)

    def test_target_none_raises_type_error(self):
        with pytest.raises(TypeError):
            binary_search([1, 2, 3], None)

    def test_mixed_types_in_array_raises_type_error(self):
        with pytest.raises(TypeError):
